import { useState, useEffect, useRef } from 'react';
import { subscribeToVitals } from './firebase';
import { GoogleGenerativeAI } from '@google/generative-ai';
import { Activity, Heart, MapPin, AlertTriangle, Send, User, Bot, Navigation } from 'lucide-react';

const genAI = new GoogleGenerativeAI("AIzaSyBOYm08vtnp3v95Nw5HnKyTnzn-v8XSkzk");
const model = genAI.getGenerativeModel({ 
  model: "gemini-2.5-flash",
  systemInstruction: "You are a highly professional, empathetic, and knowledgeable medical assistant chatbot embedded in the 'Smart Care' application. Your primary user is Senthil kumar. You analyze the real-time vitals provided to you (SpO2, BPM, Fall Detection, Location) and answer any questions Senthil kumar has. Always be helpful, concise, and provide medically relevant advice while advising to seek professional help in emergencies. If vitals look alarming, gently point that out. Act as a continuous monitor and companion."
});

function App() {
  const [vitals, setVitals] = useState({ bpm: 0, fall: 0, lat: 0, lon: 0, spo2: 0 });
  const [messages, setMessages] = useState([
    { role: 'model', content: "Hello Senthil. I am your Smart Care medical assistant. How can I help you regarding your vitals today?" }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    // Subscribe to Firebase vitals data
    subscribeToVitals((data) => {
      setVitals(data);
    });
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages, isLoading]);

  const handleSendMessage = async (e) => {
    e.preventDefault();
    if (!input.trim()) return;

    const userMessage = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setIsLoading(true);

    try {
      const chat = model.startChat({
        history: messages.map(msg => ({
          role: msg.role === 'model' ? "model" : "user",
          parts: [{ text: msg.content }]
        })),
        generationConfig: {
          maxOutputTokens: 1000,
        },
      });

      const promptContext = `Current Vitals Context: SpO2: ${vitals.spo2}%, BPM: ${vitals.bpm}, Fall Detected: ${vitals.fall ? "YES" : "NO"}, Location: Lat ${vitals.lat}, Lon ${vitals.lon}. User's message: ${userMessage}`;

      const result = await chat.sendMessage(promptContext);
      const response = await result.response;
      const text = response.text();

      setMessages(prev => [...prev, { role: 'model', content: text }]);
    } catch (error) {
      console.error("Error communicating with Gemini: ", error);
      // Fallback if gemini-2.5-flash fails, trying gemini-1.5-flash
      try {
        const fallbackModel = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });
        const fallbackChat = fallbackModel.startChat({
            history: messages.map(msg => ({
              role: msg.role === 'model' ? "model" : "user",
              parts: [{ text: msg.content }]
            })),
        });
        const result = await fallbackChat.sendMessage(`Current Vitals Context: SpO2: ${vitals.spo2}%, BPM: ${vitals.bpm}, Fall Detected: ${vitals.fall ? "YES" : "NO"}. User's message: ${userMessage}`);
        setMessages(prev => [...prev, { role: 'model', content: result.response.text() }]);
      } catch (err) {
          setMessages(prev => [...prev, { role: 'model', content: "I'm having trouble connecting to my brain right now. Please try again later." }]);
      }
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <>
      <header className="dashboard-header">
        <div className="header-top">
          <div className="app-title">
            <Activity className="icon" />
            Smart Care
          </div>
          <div className="user-welcome">
            Monitoring <span>Senthil kumar</span>
          </div>
        </div>

        <div className="vitals-grid">
          {/* SpO2 Card */}
          <div className={\`vital-card \${vitals.spo2 < 90 ? 'danger' : (vitals.spo2 < 95 ? 'warning' : 'normal')}\`}>
            <div className="card-header">
              <Activity className="card-icon" style={{ color: 'var(--accent-secondary)' }} />
              Blood Oxygen (SpO2)
            </div>
            <div className="card-value">
              {vitals.spo2} <span className="card-unit">%</span>
            </div>
          </div>

          {/* BPM Card */}
          <div className={\`vital-card \${(vitals.bpm < 60 || vitals.bpm > 100) ? 'warning' : 'normal'}\`}>
            <div className="card-header">
              <Heart className="card-icon" style={{ color: 'var(--danger)' }} />
              Heart Rate (BPM)
            </div>
            <div className="card-value">
              {vitals.bpm} <span className="card-unit">bpm</span>
            </div>
          </div>

          {/* Fall Detection Card */}
          <div className={\`vital-card \${vitals.fall ? 'danger' : 'normal'}\`}>
            <div className="card-header">
              <AlertTriangle className="card-icon" style={{ color: vitals.fall ? 'var(--danger)' : 'var(--text-muted)' }} />
              Fall Detection
            </div>
            <div className="card-value" style={{ color: vitals.fall ? 'var(--danger)' : 'var(--text-main)', fontSize: '1.5rem' }}>
              {vitals.fall ? "Fall Detected!" : "Safe"}
            </div>
          </div>

          {/* Location Card */}
          <div className="vital-card info">
            <div className="card-header">
              <MapPin className="card-icon" style={{ color: 'var(--accent-primary)' }} />
              Current Location
            </div>
            <div className="card-value" style={{ fontSize: '1.25rem' }}>
              {vitals.lat.toFixed(4)}, {vitals.lon.toFixed(4)}
            </div>
            <a 
              href={\`https://www.google.com/maps?q=\${vitals.lat},\${vitals.lon}\`} 
              target="_blank" 
              rel="noreferrer"
              className="btn-map"
            >
              <Navigation size={18} /> View on Maps
            </a>
          </div>
        </div>
      </header>

      <main className="chat-container">
        <div className="chat-messages">
          {messages.map((msg, idx) => (
            <div key={idx} className={\`message \${msg.role === 'model' ? 'ai' : 'user'}\`}>
              <div className="message-avatar">
                {msg.role === 'model' ? <Bot size={20} /> : <User size={20} />}
              </div>
              <div className="message-content">
                {/* Simple rendering, ideally use marked for markdown */}
                {msg.content.split('\\n').map((line, i) => (
                  <p key={i}>{line}</p>
                ))}
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="message ai">
              <div className="message-avatar">
                <Bot size={20} />
              </div>
              <div className="message-content">
                <div className="typing-indicator">
                  <div className="typing-dot"></div>
                  <div className="typing-dot"></div>
                  <div className="typing-dot"></div>
                </div>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        <div className="chat-input-container">
          <form className="chat-input-wrapper" onSubmit={handleSendMessage}>
            <input
              type="text"
              className="chat-input"
              placeholder="Ask your medical assistant..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              disabled={isLoading}
            />
            <button type="submit" className="btn-send" disabled={isLoading || !input.trim()}>
              <Send size={20} />
            </button>
          </form>
        </div>
      </main>
    </>
  );
}

export default App;
